```sql
-- Method 1: Window Function (Recommended)
SELECT salary FROM (
    SELECT salary, DENSE_RANK() OVER (ORDER BY salary DESC) as rnk
    FROM employees
) as t
WHERE rnk = N;

-- Method 2: Correlated Subquery (Classic logic)
SELECT salary FROM employees e1
WHERE (N-1) = (SELECT COUNT(DISTINCT salary) FROM employees e2 WHERE e2.salary > e1.salary);

-- Method 3: 2nd Highest specifically (Simple Subquery)
SELECT MAX(salary) FROM employees WHERE salary < (SELECT MAX(salary) FROM employees);
```

